import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/macos-password-prompt.BkxO9RJk.js";const s=JSON.parse(`{"title":"Installare Java su macOS","description":"Una guida passo per passo su come installare Java su macOS.","frontmatter":{"title":"Installare Java su macOS","description":"Una guida passo per passo su come installare Java su macOS.","authors":["dexman545","ezfe"],"next":false,"files":[]},"headers":[],"relativePath":"it_it/players/installing-java/macos.md","filePath":"translated/it_it/players/installing-java/macos.md","lastUpdated":1770561656000}`);var c={name:`it_it/players/installing-java/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installare Java su macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Installare Java su macOS”">​</a></h1><p>Questa guida ti spiegherà come installare Java 21 su macOS.</p><p>Il Launcher di Minecraft ha la sua versione di Java installata, quindi questa sezione è rilevante solo se vuoi usare l&#39;installer <code>.jar</code> di Fabric, oppure se vuoi usare il <code>.jar</code> del Server di Minecraft.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Controlla Se Java È Già Installato <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Controlla Se Java È Già Installato”">​</a></h2><p>Nel Terminale (che trovi in <code>/Applications/Utilities/Terminal.app</code>) scrivi ciò che segue, e premi <kbd>Invio</kbd>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/libexec/java_home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)/bin/java --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Dovresti vedere qualcosa del genere:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Prendi nota del numero della versione: nell&#39;esempio sopra è <code>21.0.9</code>.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Per usare Minecraft 1.21.11, ti servirà almeno Java 21 installato.</p><p>Se questo comando mostra una versione inferiore a 21, allora dovrai aggiornare la versione di Java già esistente; continua a seguire questa pagina.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Scaricare e Installare Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Scaricare e Installare Java 21”">​</a></h2><p>Consigliamo di usare la <a href="https://adoptium.net/temurin/releases?version=21&amp;os=mac&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">build di OpenJDK 21 da Adoptium</a>:</p><p><img src="/assets/players/installing-java/macos-download-java.png" alt="Pagina da cui si scarica Temurin Java" loading="lazy"></p><p>Assicurati di aver selezionato la versione &quot;21 - LTS&quot;, e scegli il formato d&#39;installazione <code>.PKG</code>. Dovresti anche far attenzione all&#39;architettura, a seconda del processore del tuo sistema:</p><ul><li>Se hai un processore Apple della serie M, scegli <code>aarch64</code> (predefinito)</li><li>Se hai un processore Intel, scegli <code>x64</code></li><li>Puoi seguire queste <a href="https://support.apple.com/en-us/116943" target="_blank" rel="noreferrer">istruzioni per determinare il processore del tuo Mac</a></li></ul><p>Dopo aver scaricato l&#39;installer <code>.pkg</code>, aprilo e segui le istruzioni:</p><p><img src="/assets/players/installing-java/macos-installer.png" alt="Installer di Temurin Java" loading="lazy"></p><p>Dovrai inserire la tua password di amministratore per completare l&#39;installazione:</p><p><img src="/assets/players/installing-java/macos-password-prompt.png" alt="Finestra di autenticazione di macOS" loading="lazy"></p><h3 id="using-homebrew" tabindex="-1">Usando Homebrew <a class="header-anchor" href="#using-homebrew" aria-label="Permalink to “Usando Homebrew”">​</a></h3><p>Se hai già installato <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a>, puoi alternativamente usare <code>brew</code> per installare Java 21:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> temurin@21</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Verifica che Java 21 Sia Installato <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Verifica che Java 21 Sia Installato”">​</a></h2><p>Quando l&#39;installazione è stata completata, puoi verificare che Java 21 sia attivo aprendo di nuovo il Terminale e scrivendo <code>$(/usr/libexec/java_home -v 21)/bin/java --version</code>.</p><p>Se il comando funziona correttamente, dovresti vedere qualcosa del genere:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Se incontri dei problemi, sentiti libero di chiedere aiuto nel server <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> nel canale <code>#player-support</code>.</p>`,27)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};